import{c as s,Q as n,j as i,m as e}from"./chunks/framework.D9IbVcwA.js";const b=JSON.parse('{"title":"030-gui-wm-basic-2 · 窗口管理器","description":"","frontmatter":{"title":"030-gui-wm-basic-2 · 窗口管理器"},"headers":[],"relativePath":"read-through/030-gui-wm-basic-2.md","filePath":"read-through/030-gui-wm-basic-2.md","lastUpdated":1779686691000}'),p={name:"read-through/030-gui-wm-basic-2.md"};function l(r,a,t,o,d,h){return n(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="_030-2-read-through-window-windowmanager" tabindex="-1">030-2 Read-through: Window + WindowManager <a class="header-anchor" href="#_030-2-read-through-window-windowmanager" aria-label="Permalink to &quot;030-2 Read-through: Window + WindowManager&quot;">​</a></h1><h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h2><p>本文 walkthrough 覆盖 Window 类和 WindowManager 类的完整实现。Window 封装了一个 GUI 窗口的所有可视元素——标题栏、关闭按钮、内容区、离屏画布。WindowManager 是窗口的&quot;大脑&quot;，负责创建/销毁窗口、维护 Z-序、管理焦点、响应鼠标事件、执行桌面合成。这两个类构成了 Cinux GUI 的核心框架。</p><p>关键设计决策：窗口用指针数组管理以避免拷贝，Z-序通过数组索引隐式表达，焦点自动跟随最顶层窗口。</p><h2 id="架构图" tabindex="-1">架构图 <a class="header-anchor" href="#架构图" aria-label="Permalink to &quot;架构图&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                WindowManager (singleton)</span></span>
<span class="line"><span>                +---------------------------+</span></span>
<span class="line"><span>                | windows_[0..63]           |  ← Z-ordered pointer array</span></span>
<span class="line"><span>                |   [0] Window* (bottom)    |</span></span>
<span class="line"><span>                |   [1] Window*             |</span></span>
<span class="line"><span>                |   [n] Window* (top)       |  ← focused_</span></span>
<span class="line"><span>                +---------------------------+</span></span>
<span class="line"><span>                     |              |</span></span>
<span class="line"><span>                     v              v</span></span>
<span class="line"><span>              +------------+  +------------+</span></span>
<span class="line"><span>              | Window     |  | Window     |</span></span>
<span class="line"><span>              | id_=1      |  | id_=2      |</span></span>
<span class="line"><span>              | x_,y_,w_,h |  | x_,y_,w_,h |</span></span>
<span class="line"><span>              | canvas_    |  | canvas_    |</span></span>
<span class="line"><span>              | title_[]   |  | title_[]   |</span></span>
<span class="line"><span>              | visible_   |  | visible_   |</span></span>
<span class="line"><span>              | focused_   |  | focused_   |</span></span>
<span class="line"><span>              +------------+  +------------+</span></span>
<span class="line"><span>                   |                |</span></span>
<span class="line"><span>                   v                v</span></span>
<span class="line"><span>              +----------+    +----------+</span></span>
<span class="line"><span>              | Canvas   |    | Canvas   |</span></span>
<span class="line"><span>              | (offscr) |    | (offscr) |</span></span>
<span class="line"><span>              +----------+    +----------+</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    composite() flow:</span></span>
<span class="line"><span>    Screen Canvas ← clear(Desktop Color)</span></span>
<span class="line"><span>                   ← blit windows[0]</span></span>
<span class="line"><span>                   ← blit windows[1]</span></span>
<span class="line"><span>                   ← blit windows[n]   (top-most)</span></span>
<span class="line"><span>                   ← draw_cursor()</span></span>
<span class="line"><span>                   ← flip()</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br></div></div><h2 id="代码精讲" tabindex="-1">代码精讲 <a class="header-anchor" href="#代码精讲" aria-label="Permalink to &quot;代码精讲&quot;">​</a></h2><h3 id="window-hpp-—-window-类声明" tabindex="-1">window.hpp — Window 类声明 <a class="header-anchor" href="#window-hpp-—-window-类声明" aria-label="Permalink to &quot;window.hpp — Window 类声明&quot;">​</a></h3><p>Window 的常量定义了视觉规范：标题栏高度 20px，关闭按钮 14x14px，标题最长 63 字符，默认窗口 320x240。颜色方案是硬编码的 0x00RRGGBB 格式——标题栏背景用钢蓝色（0x336699），标题文字白色，关闭按钮红色，内容区浅灰，边框深灰。</p><p>构造函数接收标题、位置和尺寸，自动分配唯一 ID。Window 的公共接口都是非虚方法——draw_title_bar、draw_content、blit_to、set_position、resize、set_title、is_close_button_hit、contains，以及各种 getter/setter。没有虚函数，也没有继承层次——tag 030 的 Window 是一个纯粹的值-绘制类。</p><p>Window 是 non-copyable 的（拷贝构造和赋值都被 delete），因为每个 Window 独占一个 Canvas（Canvas 持有通过 init(w,h) 分配的 back_buf_ 堆内存）。如果允许拷贝，两个 Window 指向同一个 back_buf_ 会在析构时 double-free。</p><h3 id="window-cpp-—-window-实现" tabindex="-1">window.cpp — Window 实现 <a class="header-anchor" href="#window-cpp-—-window-实现" aria-label="Permalink to &quot;window.cpp — Window 实现&quot;">​</a></h3><p>构造函数的逻辑很清晰：分配 ID、初始化位置尺寸、手动复制标题字符串（零填充 + 截断），最后调用 allocate_canvas。手动复制而不是用 strncpy 是因为我们的内核没有标准库——这个模式在 Cinux 的很多地方都能看到。</p><p>draw_title_bar 分三步：先画蓝色背景矩形（覆盖标题栏整个区域），然后画一行标题文字（垂直居中），最后画红色关闭按钮方块（右上角，左右和上下都留 3px 边距）。底部有一条 1px 的边框线分隔标题栏和内容区。</p><p>draw_content 清空内容区为浅灰色（COLOR_CONTENT_BG = 0x00E0E0E0）。在 tag 030 中没有子类扩展点——内容区只是一个空灰色矩形。后续 tag 会引入 Terminal 等子类来在这里渲染自定义内容。</p><p>blit_to 是窗口从离屏到屏幕的关键桥梁。它调用目标 Canvas 的 blit 方法，把窗口的整个离屏画布（从 (0,0) 到 (w_, total_height())）一次性 blit 到屏幕上的 (x_, y_) 位置。注意 dst_x 和 dst_y 是 int32_t 类型——当窗口被拖到屏幕左侧或上方时坐标可能为负，Canvas::blit 内部会做裁剪。</p><p>hit testing 两个方法都接收屏幕坐标。contains 检查点是否在窗口矩形内（x_ 到 x_+w_, y_ 到 y_+total_height()）。is_close_button_hit 把关闭按钮的位置从窗口局部坐标转换到屏幕坐标，然后做矩形包含测试。</p><h3 id="window-manager-hpp-—-windowmanager-声明" tabindex="-1">window_manager.hpp — WindowManager 声明 <a class="header-anchor" href="#window-manager-hpp-—-windowmanager-声明" aria-label="Permalink to &quot;window_manager.hpp — WindowManager 声明&quot;">​</a></h3><p>WindowManager 是一个 Meyers&#39; singleton，通过 instance() 静态方法获取。它管理最多 64 个窗口指针。常量 DESKTOP_COLOR 定义了深青色桌面背景。</p><p>核心数据结构是一个 Window* 数组 windows_[MAX_WINDOWS]，用 count_ 追踪有效数量。focused_ 指针直接指向最顶层窗口，避免每次都算 count_ - 1。</p><p>拖拽状态用三个成员表示：dragging_ 布尔标志、drag_offset_x_ 和 drag_offset_y_ 偏移量。</p><p>光标位图 k_cursor_bitmap 是一个 16 行的 uint16_t 数组，编码了经典箭头形状。MSB 是最左边的像素，1 表示填充，0 表示透明。</p><h3 id="window-manager-cpp-—-windowmanager-实现" tabindex="-1">window_manager.cpp — WindowManager 实现 <a class="header-anchor" href="#window-manager-cpp-—-windowmanager-实现" aria-label="Permalink to &quot;window_manager.cpp — WindowManager 实现&quot;">​</a></h3><p>instance() 就是标准的 Meyers&#39; singleton：<code>static WindowManager wm; return wm;</code>。零初始化，第一次调用时构造，程序结束前析构。</p><p>create 方法先检查容量，然后 new 一个 Window 对象（位置交错），绘制标题栏和内容，更新焦点，返回 ID。交错位置的计算是 <code>count_ * 30</code>——每个新窗口相对上一个偏移 30px，这样连续创建的窗口不会完全重叠。</p><p>destroy 通过 find_index 定位窗口，然后调 remove_at。remove_at 做三件事：delete 对象、shift 后续指针、清空末尾槽位、减少计数。如果被删的是焦点窗口就重新计算焦点。</p><p>raise 是 Z-序管理的核心操作。实现方式是把目标窗口指针从当前位置抽出来，上面的窗口依次往下挪一位，然后放到数组末尾：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Window</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> win </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> windows_[idx];</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">uint32_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> idx; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> count_ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    windows_[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> windows_[i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">windows_[count_ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> win;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这是一个 O(n) 的数组 shift 操作。对于最多 64 个窗口来说性能完全不是问题。如果窗口数量增长到上千个，可以考虑用链表或跳表。</p><p>composite 的流程是：clear → blit all windows → draw_cursor → flip。先清屏为深青色桌面背景，然后从低 Z-order 到高依次 blit 各窗口的离屏画布，再画鼠标光标，最后 flip 到硬件 framebuffer。</p><p>handle_mouse 实现了拖拽状态机。MouseDown 做 hit test → 关闭按钮检测 → raise → 标题栏检测 → 开始拖拽。MouseMove 在拖拽状态下移动窗口。MouseUp 结束拖拽。</p><p>handle_key 在 tag 030 中是一个空操作——<code>(void)ev;</code>。键盘事件虽然被入队并在 tick 回调里分发给 handle_key，但当前版本不做任何处理，留待后续 tag 实现。</p><p>update_focus 清除所有窗口的 focused 标记，然后给最顶层窗口设上。这是一个 O(n) 操作，但 n 最大 64，无所谓。</p><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><h3 id="决策-指针数组-vs-链表" tabindex="-1">决策：指针数组 vs 链表 <a class="header-anchor" href="#决策-指针数组-vs-链表" aria-label="Permalink to &quot;决策：指针数组 vs 链表&quot;">​</a></h3><p><strong>问题</strong>: 窗口用什么数据结构管理？ <strong>本项目的做法</strong>: 固定容量 Window* 指针数组。 <strong>备选方案</strong>: 链表，或 std::vector 等动态容器。 <strong>为什么不选备选方案</strong>: 链表不支持 O(1) 随机访问，hit test 和 compositing 需要遍历所有窗口，链表的 cache 友好性也差。动态容器需要堆分配器支持，而我们的内核没有 STL。固定数组简单、cache 友好、没有碎片问题，64 个窗口的上限对于教学 OS 绰绰有余。</p><h3 id="决策-焦点-最顶层窗口" tabindex="-1">决策：焦点 = 最顶层窗口 <a class="header-anchor" href="#决策-焦点-最顶层窗口" aria-label="Permalink to &quot;决策：焦点 = 最顶层窗口&quot;">​</a></h3><p><strong>问题</strong>: 焦点策略用什么？ <strong>本项目的做法</strong>: 焦点自动跟随最顶层窗口（click-to-raise + click-to-focus）。 <strong>备选方案</strong>: 焦点和 Z-序分离（click-to-focus 但不 raise，需要额外操作来 raise）。 <strong>为什么不选备选方案</strong>: click-to-raise + click-to-focus 是最简单直观的行为，几乎所有的简单窗口管理器都这么做。分离焦点和 Z-序增加了复杂度，对于教学 OS 没有太大价值。</p><h2 id="扩展方向" tabindex="-1">扩展方向 <a class="header-anchor" href="#扩展方向" aria-label="Permalink to &quot;扩展方向&quot;">​</a></h2><ul><li>窗口缩放：在标题栏或内容区边角添加 resize 手柄 (难度 ⭐⭐)</li><li>最小化/最大化：添加窗口状态（normal/minimized/maximized）和任务栏 (难度 ⭐⭐)</li><li>窗口装饰主题：把颜色常量抽成可配置的主题结构 (难度 ⭐)</li><li>损坏追踪（damage tracking）：记录哪些区域需要重绘，只 blit 脏区域 (难度 ⭐⭐⭐)</li><li>窗口动画：raise/destroy 时添加淡入淡出效果 (难度 ⭐⭐⭐)</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>OSDev Wiki: <a href="https://wiki.osdev.org/PS/2_Mouse" target="_blank" rel="noreferrer">PS/2 Mouse</a> — 事件类型参考</li><li>SerenityOS: <a href="https://github.com/SerenityOS/serenity/tree/master/Userland/Services/WindowServer" target="_blank" rel="noreferrer">WindowServer</a> — 损坏追踪和合成器架构参考</li><li>Linux: <a href="https://www.x.org/wiki/" target="_blank" rel="noreferrer">Early X11 Window Managers</a> — 客户端-服务器窗口管理对比</li></ul>`,42)])])}const w=s(p,[["render",l]]);export{b as __pageData,w as default};
